import boto3
import json
from decimal import Decimal
from urllib.parse import urlparse, parse_qs

dynamodb = boto3.resource('dynamodb', endpoint_url='http://localhost:4566')
table = dynamodb.Table('Accounts')


class DecimalEncoder(json.JSONEncoder):
    def default(self, obj):
        if isinstance(obj, Decimal):
            return float(obj)
        return super().default(obj)


def respond(status_code: int, body: dict) -> dict:
    return {
        'statusCode': status_code,
        'headers': {
            'Content-Type': 'application/json',
            'Access-Control-Allow-Origin': '*',
        },
        'body': json.dumps(body, cls=DecimalEncoder),
    }


def get_account(merchant_id: str) -> dict:
    result = table.get_item(Key={'merchant_id': merchant_id})
    item = result.get('Item')
    if not item:
        return respond(404, {'error': 'Comercio no encontrado'})
    return respond(200, item)


def handler(event, context):
    method = event.get('requestContext', {}).get('http', {}).get('method', 'GET')
    path = event.get('rawPath', '/')
    qs = parse_qs(event.get('rawQueryString', ''))

    # GET /account?merchant_id=NAVE-001
    if method == 'GET' and path == '/account':
        merchant_id = qs.get('merchant_id', [None])[0]
        if not merchant_id:
            return respond(400, {'error': 'merchant_id requerido'})
        return get_account(merchant_id)

    # GET /health
    if method == 'GET' and path == '/health':
        return respond(200, {'status': 'ok', 'version': '2.1.0'})

    return respond(404, {'error': 'Ruta no encontrada'})

